class Task:
    def __init__(self, title, done):
        self.title = title
        self.done = done


def save_tasks(tasks, path):
    with open(path, "w") as file:
        for task in tasks:
            file.write(f"{task.title}|{task.done}\n")


def load_tasks(path):
    tasks = []
    with open(path, "r") as file:
        for line in file:
            line = line.strip()
            if line:
                title, done_text = line.split("|")
                tasks.append(Task(title, done_text == "True"))
    return tasks


def count_done(tasks):
    total = 0
    for task in tasks:
        if task.done:
            total += 1
    return total


def todo_titles(tasks):
    titles = []
    for task in tasks:
        if not task.done:
            titles.append(task.title)
    return titles


tasks = [
    Task("Plan project", False),
    Task("Write code", True),
    Task("Test app", False)
]

save_tasks(tasks, "tasks.txt")
loaded_tasks = load_tasks("tasks.txt")
done_count = count_done(loaded_tasks)
todo_text = ", ".join(todo_titles(loaded_tasks))

print(f"Total: {len(loaded_tasks)}")
print(f"Done: {done_count}")
print(f"Todo: {todo_text}")
